#include <stdio.h>

int main() {
    int T, N;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        if (scanf("%d", &N) != 1) return 0;
        int i = 1;
        while (i <= N) {
            printf("%d", i * i);
            if (i < N) printf(" ");
            i++;
        }
        if (T) printf("\n");
    }
    return 0;
}

