const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
if (input.length === 0) process.exit(0);
let t = parseInt(input[0], 10);
let idx = 1;
let outputs = [];
for (let caseNum = 0; caseNum < t; caseNum++) {
  let n = parseInt(input[idx++], 10);
  let line = [];
  let i = 1;
  while (i <= n) {
    line.push(i * i);
    i++;
  }
  outputs.push(line.join(' '));
}
console.log(outputs.join('\n'));

